import "./styles/BorrowedBooks.css";

const borrowed = [
  {
    title: "Harry Potter",
    category: "Fantasy",
    date: "12 Jan 2026",
    return: "22 Jan 2026",
    status: "Due"
  },
  {
    title: "Clean Code",
    category: "Technology",
    date: "05 Jan 2026",
    return: "15 Jan 2026",
    status: "Returned"
  }
];

function BorrowedBooks() {
  return (
    <div className="borrow-page">
      <h1 className="borrow-title">My Borrowed Books</h1>

      {borrowed.map((b, i) => (
        <div key={i} className="borrow-card">
          <h3>{b.title}</h3>
          <p>Category: {b.category}</p>
          <p>Borrowed: {b.date}</p>
          <p>Return: {b.return}</p>
          <span className={`status ${b.status.toLowerCase()}`}>
            {b.status}
          </span>
        </div>
      ))}
    </div>
  );
}

export default BorrowedBooks;
